@js:
var doc = org.jsoup.Jsoup.parse(result);
var lines = doc.select(".paly_list_btn a, .juji_list a");
if (lines.size() == 0) { "未找到剧集线路"; } else {
    function esc(s) { return String(s||"").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;"); }

    // 提取剧名
    var titleNode = doc.select(".moviedteail_tt h1");
    var titleText = titleNode.size() > 0 ? titleNode.text().trim() : doc.select("title").text().trim();

    var html = "";
    html += "<style>";
    html += "*{box-sizing:border-box;}";
    html += ".wrap{padding:8px;background:#f5f6fa;border-radius:12px;font-family:Arial;}";
    html += ".top-title{font-size:18px;font-weight:bold;text-align:center;color:#222;margin-bottom:12px;line-height:1.4;word-wrap:break-word;}";
    html += ".player-wrapper{position:relative;width:100%;aspect-ratio:16/9;border-radius:12px;overflow:hidden;background:#000;margin-bottom:8px;}";
    html += ".player-wrapper iframe{width:100%;height:100%;border:none;}";
    /* 新增历史记录提示样式 */
    html += ".history-tip{font-size:13px;color:#666;margin-bottom:10px;padding:4px 8px;background:#eef2ff;border-radius:6px;display:inline-block;}";
    html += ".line-tabs{display:flex;gap:8px;flex-wrap:wrap;}";
    html += ".line-tabs button{flex:0 0 auto;min-width:44px;border:none;padding:8px 12px;border-radius:8px;background:#eef2ff;font-size:14px;font-weight:600;cursor:pointer;text-align:center;}";
    html += ".line-tabs button.active{background:#4f8cff;color:#fff;}";
    html += ".loading-txt{color:#ccc;text-align:center;position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);font-size:14px;}";
    html += "</style>";

    html += "<div class='wrap'>";

    // 如果提取到了剧名，就显示在最上方
    if (titleText) {
        html += "<div class='top-title'>" + esc(titleText) + "</div>";
    }

    html += "<div class='player-wrapper' id='playerBox'>";
    html += "<div class='loading-txt'>准备播放...</div>";
    html += "</div>";

    // 预留历史记录提示的容器
    html += "<div id='historyTipWrapper' style='display:none;'><div class='history-tip' id='historyTip'></div></div>";

    html += "<div class='line-tabs' id='lineTabs'>";
    for (var i = 0; i < lines.size(); i++) {
        var name = lines.get(i).text().trim() || ("集数" + (i + 1));
        var href = lines.get(i).attr("href");
        html += "<button id='tab_" + i + "' data-href='" + href + "' class='' onclick='switchLine(this," + i + ")'>" + esc(name) + "</button>";
    }
    html += "</div>";
    html += "</div>";

    html += "<script>";
    // 安全地将当前剧名传递给 JS，作为 LocalStorage 的独立 key
    html += "var pageTitle = decodeURIComponent('" + encodeURIComponent(titleText) + "');";
    html += "var storageKey = 'cz_hist_' + pageTitle;";

    html += "function switchLine(btn, idx) {";
    html += "  var tabs = document.querySelectorAll('.line-tabs button');";
    html += "  for (var i = 0; i < tabs.length; i++) tabs[i].classList.remove('active');";
    html += "  btn.classList.add('active');";

    // 保存独立历史记录并更新UI
    html += "  var epName = btn.innerText;";
    html += "  try { ";
    html += "    localStorage.setItem(storageKey, JSON.stringify({idx: idx, name: epName}));";
    html += "    var tipWrapper = document.getElementById('historyTipWrapper');";
    html += "    tipWrapper.style.display = 'block';";
    html += "    document.getElementById('historyTip').innerHTML = '🎬 你已观看到：<span style=\"color:#4f8cff;font-weight:bold;\">' + epName + '</span>';";
    html += "  } catch(e) {}";

    // 播放逻辑
    html += "  var targetUrl = btn.getAttribute('data-href');";
    html += "  var playerBox = document.getElementById('playerBox');";
    html += "  playerBox.innerHTML = '<div class=\"loading-txt\">解析真实播放源中...</div>';";

    html += "  fetch(targetUrl).then(function(res){return res.text();}).then(function(text){";
    html += "    var realSrc = '';";
    html += "    var iframeReg = /<iframe[^>]+src=['\"]([^'\"]+)['\"]/i;";
    html += "    var match = text.match(iframeReg);";
    html += "    if(match && match[1] && match[1].indexOf('about:blank') === -1) {";
    html += "      realSrc = match[1];";
    html += "    } else {";
    html += "      var jsReg = /player_aaaa\\s*=\\s*(\\{.*?\\})/;";
    html += "      var jsMatch = text.match(jsReg);";
    html += "      if(jsMatch && jsMatch[1]){ try { var obj = JSON.parse(jsMatch[1]); realSrc = obj.url; } catch(e) {} }";
    html += "    }";

    html += "    if(realSrc){";
    html += "      if(realSrc.indexOf('//') === 0) realSrc = 'https:' + realSrc;";
    html += "      else if(realSrc.indexOf('/') === 0) realSrc = 'https://www.cz01.org' + realSrc;";
    html += "      playerBox.innerHTML = '<iframe src=\"' + realSrc + '\" allowfullscreen=\"true\" webkitallowfullscreen=\"true\" mozallowfullscreen=\"true\"></iframe>';";
    html += "    } else {";
    html += "      playerBox.innerHTML = '<div class=\"loading-txt\">无法提取源，<a href=\"' + targetUrl + '\" style=\"color:#4f8cff;\">点击跳转网页播放</a></div>';";
    html += "    }";
    html += "  }).catch(function(err){";
    html += "    playerBox.innerHTML = '<div class=\"loading-txt\">网络请求失败，<a href=\"' + targetUrl + '\" style=\"color:#4f8cff;\">点击跳转网页播放</a></div>';";
    html += "  });";
    html += "}";

    // 初始化检查独立历史记录
    html += "setTimeout(function(){";
    html += "  var histStr = localStorage.getItem(storageKey);";
    html += "  var tabs = document.querySelectorAll('.line-tabs button');";
    html += "  var targetBtn = tabs[0];";
    html += "  if(histStr) {";
    html += "    try {";
    html += "      var hist = JSON.parse(histStr);";
    html += "      if(tabs[hist.idx]) { targetBtn = tabs[hist.idx]; }";
    html += "    } catch(e) {}";
    html += "  }";
    html += "  if(targetBtn) targetBtn.click();";
    html += "}, 100);";
    html += "</script>";

    html;
}

